import{_ as e,o as d,c as a,ag as o}from"./chunks/framework.D54qew5K.js";const u=JSON.parse('{"title":"MCP 工具参考","description":"容器内 Agent 可调用的 MCP 工具完整列表","frontmatter":{"title":"MCP 工具参考","description":"容器内 Agent 可调用的 MCP 工具完整列表"},"headers":[],"relativePath":"reference/mcp-tools.md","filePath":"reference/mcp-tools.md","lastUpdated":1774526771000}'),r={name:"reference/mcp-tools.md"};function i(l,t,c,n,s,h){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="mcp-工具参考" tabindex="-1">MCP 工具参考 <a class="header-anchor" href="#mcp-工具参考" aria-label="Permalink to &quot;MCP 工具参考&quot;">​</a></h1><p>AeroLoongClaw 在容器内运行一个 <a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">MCP</a> Stdio 服务器（<code>container/agent-runner/src/ipc-mcp-stdio.ts</code>），向容器内的 Agent 暴露 IPC 工具。Agent 通过这些工具与宿主机通信，实现消息发送、任务调度、技能管理、授权审计等功能。</p><p>生成类工具（语音、图像、视频、音乐）已移至 <code>mcp__MiniMaxGeneration__</code> 系列工具。</p><h2 id="消息-messaging" tabindex="-1">消息 (Messaging) <a class="header-anchor" href="#消息-messaging" aria-label="Permalink to &quot;消息 (Messaging)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具名称</th><th>说明</th></tr></thead><tbody><tr><td><code>send_message</code></td><td>向当前会话发送文字消息、媒体文件或带发送者身份的消息</td></tr></tbody></table><h2 id="任务调度-task-scheduling" tabindex="-1">任务调度 (Task Scheduling) <a class="header-anchor" href="#任务调度-task-scheduling" aria-label="Permalink to &quot;任务调度 (Task Scheduling)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具名称</th><th>说明</th></tr></thead><tbody><tr><td><code>schedule_task</code></td><td>创建定时或周期任务，支持 cron 表达式、间隔时间和一次性调度</td></tr><tr><td><code>list_tasks</code></td><td>列出当前会话可见的所有已调度任务</td></tr><tr><td><code>pause_task</code></td><td>暂停一个已调度的任务</td></tr><tr><td><code>resume_task</code></td><td>恢复一个已暂停的任务</td></tr><tr><td><code>cancel_task</code></td><td>取消并删除一个已调度的任务</td></tr></tbody></table><h2 id="技能管理-skills" tabindex="-1">技能管理 (Skills) <a class="header-anchor" href="#技能管理-skills" aria-label="Permalink to &quot;技能管理 (Skills)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具名称</th><th>说明</th></tr></thead><tbody><tr><td><code>list_installed_skills</code></td><td>列出宿主机当前已安装的所有运行时技能</td></tr><tr><td><code>install_skill</code></td><td>从 ClawHub 或 GitHub 安装运行时技能</td></tr><tr><td><code>promote_local_skill</code></td><td>将容器内 <code>/workspace/group</code> 下的本地技能草稿提升为宿主机运行时技能</td></tr><tr><td><code>remove_skill</code></td><td>从宿主机移除已安装的运行时技能</td></tr><tr><td><code>disable_skill</code></td><td>禁用已安装的运行时技能（记录审计日志，支持回滚）</td></tr><tr><td><code>rollback_skill_change</code></td><td>回滚最近一次技能变更</td></tr><tr><td><code>search_skills</code></td><td>在 SkillHub 注册表中搜索可安装的技能</td></tr></tbody></table><h2 id="授权管理-authorization" tabindex="-1">授权管理 (Authorization) <a class="header-anchor" href="#授权管理-authorization" aria-label="Permalink to &quot;授权管理 (Authorization)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具名称</th><th>说明</th></tr></thead><tbody><tr><td><code>authorize_sender</code></td><td>授权一个企业微信发件人</td></tr><tr><td><code>authorization_status</code></td><td>查看当前授权策略和最近审计事件快照</td></tr><tr><td><code>restore_default_authorization_policy</code></td><td>恢复默认授权策略（自动允许，后审计）</td></tr></tbody></table><h2 id="插件管理-plugins" tabindex="-1">插件管理 (Plugins) <a class="header-anchor" href="#插件管理-plugins" aria-label="Permalink to &quot;插件管理 (Plugins)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具名称</th><th>说明</th></tr></thead><tbody><tr><td><code>install_plugin</code></td><td>从 GitHub 安装 Anthropic Knowledge Work 插件</td></tr><tr><td><code>list_plugins</code></td><td>列出所有已安装的插件及其关联技能</td></tr><tr><td><code>remove_plugin</code></td><td>移除已安装的插件及其所有关联技能</td></tr></tbody></table><h2 id="多模态-multimodal" tabindex="-1">多模态 (Multimodal) <a class="header-anchor" href="#多模态-multimodal" aria-label="Permalink to &quot;多模态 (Multimodal)&quot;">​</a></h2><p>:::note 语音、图像、视频生成工具已从 IPC MCP 中移除，改用 <code>mcp__MiniMaxGeneration__</code> 系列工具：</p><ul><li><code>mcp__MiniMaxGeneration__text_to_audio</code> — 语音合成</li><li><code>mcp__MiniMaxGeneration__text_to_image</code> — 图像生成</li><li><code>mcp__MiniMaxGeneration__generate_video</code> — 视频生成</li><li><code>mcp__MiniMaxGeneration__music_generation</code> — 音乐生成</li></ul><p>:::</p><table tabindex="0"><thead><tr><th>工具名称</th><th>说明</th></tr></thead><tbody><tr><td><code>generate_music</code></td><td>生成歌词并调用音乐生成（<code>auto_lyrics</code> 参数可自动从 prompt 生成歌词）</td></tr></tbody></table><h2 id="群组与会话-group-session" tabindex="-1">群组与会话 (Group &amp; Session) <a class="header-anchor" href="#群组与会话-group-session" aria-label="Permalink to &quot;群组与会话 (Group &amp; Session)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具名称</th><th>说明</th></tr></thead><tbody><tr><td><code>register_group</code></td><td>注册一个新群组，使 Agent 能够响应该群组的消息</td></tr><tr><td><code>reset_session</code></td><td>重置当前会话上下文，清空对话历史（长期文件 <code>AGENTS.md</code>、<code>SOUL.md</code>、<code>USER.md</code>、<code>MEMORY.md</code> 会被保留）</td></tr></tbody></table><h2 id="工具调用约定" tabindex="-1">工具调用约定 <a class="header-anchor" href="#工具调用约定" aria-label="Permalink to &quot;工具调用约定&quot;">​</a></h2><p>所有工具均通过 MCP stdio 传输调用。Agent 传入参数后，结果以异步事件返回（消息会通过 IPC 写入宿主机文件，宿主机处理完毕后再通过 IPC 响应）。</p><h3 id="通用参数" tabindex="-1">通用参数 <a class="header-anchor" href="#通用参数" aria-label="Permalink to &quot;通用参数&quot;">​</a></h3><p>大多数工具无需显式参数，直接调用即可。部分工具需要指定目标群组或资源名称。</p><h3 id="ipc-写文件原子性" tabindex="-1">IPC 写文件原子性 <a class="header-anchor" href="#ipc-写文件原子性" aria-label="Permalink to &quot;IPC 写文件原子性&quot;">​</a></h3><p>工具向 <code>/workspace/ipc/</code> 目录写入 JSON 文件时，使用 <code>临时文件 → rename</code> 的原子写入模式，并注入 <code>_writtenAt</code> 时间戳供宿主机测量 IPC 延迟。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./config.html">配置参考</a> — 环境变量完整列表</li><li><a href="./../usage/skills.html">Skills 技能系统</a> — 运行时技能使用指南</li><li><a href="./../usage/multimodal.html">多模态能力</a> — MiniMax 生成工具说明</li></ul>',28)])])}const p=e(r,[["render",i]]);export{u as __pageData,p as default};
